export const seedDatabase = async () => {
    try {
        const count = await Place.countDocuments();
        if (count > 0) {
            console.log(`ℹ️ Database already has ${count} places. Skipping seed.`);
            return;
        }
        console.log("🌱 Database is empty. Starting seed process...");
        // 1. Insert global places
        for (const p of worldDestinations) {
            await Place.create({
                ...p,
                state: "Global",
                country: p.country
            });
        }
        // 2. Insert India places
        for (const [stateName, placesList] of Object.entries(indiaStatesRaw)) {
            for (const p of placesList) {
                // Build mock properties for details coverage
                await Place.create({
                    name: p.name,
                    state: stateName,
                    country: "India",
                    continent: "asia",
                    emoji: p.emoji,
                    badge: p.tags[0] ? p.tags[0].toUpperCase() : "EXPLORE",
                    desc: p.desc,
                    history: p.history,
                    bestSeason: p.bestSeason,
                    types: p.types,
                    solo: `${p.name} offers safe hostels, welcoming cafes, and vibrant local sights suitable for solo trips.`,
                    couple: `Stunning vistas, romantic evening settings, and quality boutique stays make ${p.name} perfect for couples.`,
                    family: `Safe trails, family heritage walks, and kids-friendly dining places are widely available.`,
                    budget: p.budget,
                    visa: "ETA / Visa required for international visitors. Internal travelers need no permits.",
                    lang: p.lang,
                    currency: p.currency,
                    timezone: p.timezone,
                    tags: p.tags,
                    safetyRating: p.safetyRating,
                    familyRating: p.familyRating,
                    soloRating: p.soloRating,
                    coupleRating: p.coupleRating,
                    weather: "25°C Mostly Sunny",
                    temperature: 25,
                    sunrise: "05:45 AM",
                    sunset: "06:15 PM",
                    internetQuality: "Good (3G/4G/Wifi)",
                    nightlife: "Varies",
                    food: "Diverse traditional local specialties",
                    culture: "Deep spiritual roots and rich classical art heritage",
                    festivals: "Diwali, Holi, and local state celebrations",
                    emergencyContacts: "Police: 100, Ambulance: 102",
                    travelTips: "Wear comfortable walking shoes. Respect dress codes inside temples and sacred landmarks."
                });
            }
        }
        console.log("✅ Seed process finished successfully! Database is ready.");
    }
    catch (error) {
        console.error("❌ Seeding database failed:", error);
    }
};
